For each order, evaluate insertion into all existing assigns using cost-delta sampling with fallback to new assign creation, selecting the minimal marginal cost insertion while preserving all orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	nextAssignIdx := dispatch.AssignsLen
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		inserted := false
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		for tryIdx := 0; tryIdx < nextAssignIdx; tryIdx++ {
			assign := &dispatch.Assigns[tryIdx]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - oldCost
				assign.RemoveShip(shipID)
				assign.GenRoute()
				if !inserted || costDelta < bestCostDelta {
					bestCostDelta = costDelta
					bestAssignIdx = tryIdx
					inserted = true
				}
			}
		}
		if inserted && bestAssignIdx >= 0 && bestAssignIdx < nextAssignIdx {
			assign := &dispatch.Assigns[bestAssignIdx]
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
		} else {
			if nextAssignIdx >= MAXASSIGNS {
				dispatch.RenewnTotalCost()
				return dispatch
			}
			fallbackAssign := &dispatch.Assigns[nextAssignIdx]
			ok := fallbackAssign.AddShip(shipID, ori, des)
			if ok {
				fallbackAssign.GenRoute()
				nextAssignIdx++
				dispatch.AssignsLen = nextAssignIdx
			} else {
				dispatch.RenewnTotalCost()
				return dispatch
			}
		}
	}
	dispatch.AssignsLen = nextAssignIdx
	dispatch.RenewnTotalCost()
	return dispatch

